final:
module RefModule(out, inA, inB, sel);output reg [4:0] out;

    input [4:0] inA;
    input [4:0] inB;
    input sel;
  wire [4:0] _tap_out = out ^ {5{1'b0}};


    always @(inA, inB, sel) begin
        if (sel == 0) begin
            out <= inA;
        end
        else
            out <= inB;        
    end

endmodule
